+import { useState, useEffect } from "react";
+import { useNavigate, useParams, useLocation } from "react-router-dom";
+import {
+  Box,
+  Typography,
+  Button,
+  Chip,
+  Breadcrumbs,
+  Link,
+  Snackbar,
+  Alert
+} from "@mui/material";
+
+import {
+  ChevronRight,
+  ChevronDown,
+  FileText
+} from "lucide-react";
+
+import axios from "axios";
+
+import "./DiffViewer.css";
+import "./CodeViewer.css";
+
+const DiffViewer = () => {
+
+  const navigate = useNavigate();
+ const params = useParams();
+const projectKey = params.projectKey || localStorage.getItem("projectKey");
+const scanId = localStorage.getItem("scanId");
+
+
+  /* ---------------- STATES ---------------- */
+const location = useLocation();
+const selectedIssueKeys = location.state?.selectedIssues || [];
+  const [issues, setIssues] = useState([]);
+  const [fileDiffs, setFileDiffs] = useState([]);
+  const [currentIndex, setCurrentIndex] = useState(0);
+
+  const [openFiles, setOpenFiles] = useState({});
+  const [selectedFixes, setSelectedFixes] = useState({});
+
+  const [loading, setLoading] = useState(true);
+
+  const [snackbar, setSnackbar] = useState({
+    open: false,
+    message: "",
+    severity: "success"
+  });
+
+  /* ---------------- FETCH DATA ---------------- */
+useEffect(() => {
+  if (projectKey) {
+    localStorage.setItem("projectKey", projectKey);
+  }
+}, [projectKey]);
+
+  useEffect(() => {
+const fetchData = async () => {
+
+  try {
+
+    /* ---------------- FETCH SONAR ISSUES ---------------- */
+
+    const issuesRes = await axios.get(
+      `http://localhost:8080/api/scan/${projectKey}/issues/all`
+    );
+
+    const backendIssues =
+      issuesRes.data.content?.flatMap(g => g.issues) || [];
+
+    const selected = backendIssues.filter(i =>
+      selectedIssueKeys.includes(i.key)
+    );
+
+    const issueList = selected.map(issue => ({
+      id: issue.key,
+      file: issue.filePath,
+      title: issue.message,
+      severity: issue.severity.toLowerCase(),
+      line: issue.line
+    }));
+
+    setIssues(issueList);
+
+    /* ---------------- FETCH DIFF ---------------- */
+
+    const diffRes = await axios.get(
+      "http://localhost:8080/api/diff/project",
+          {
+            params: {
+              originalPath: `C:/sonar-workspace/${projectKey}`,
+              fixedPath: `C:/sonar-workspace/${projectKey}_fixed`
+            }
+          }
+        );
+
+        const mapped = diffRes.data.map(file => {
+
+          let line = 1;
+
+          return {
+            fileName: file.filePath.split("/").pop(),
+            relativePath: file.filePath,
+            differences: file.diffLines.map(d => {
+
+              const obj = {
+                lineNumber: line++,
+                originalLine: "",
+                fixedLine: "",
+                type: d.type
+              };
+
+              if (d.type === "REMOVED") {
+                obj.originalLine = d.line;
+              }
+
+              if (d.type === "ADDED") {
+                obj.fixedLine = d.line;
+              }
+
+              if (d.type === "UNCHANGED") {
+                obj.originalLine = d.line;
+                obj.fixedLine = d.line;
+              }
+
+              return obj;
+            })
+          };
+
+        });
+
+        setFileDiffs(mapped);
+        const fileMap = {};
+mapped.forEach(f => {
+  fileMap[f.relativePath] = true;
+});
+setOpenFiles(fileMap);
+
+        /* ---------- Auto select all ---------- */
+
+        const selected = {};
+        issueList.forEach(issue => {
+          selected[issue.id] = true;
+        });
+
+        setSelectedFixes(selected);
+
+      } catch (err) {
+        console.error("Diff fetch failed", err);
+      }
+
